import { serve } from "https://deno.land/std@0.168.0/http/server.ts";
import { createClient } from "https://esm.sh/@supabase/supabase-js@2";
import { Logger, withRetry } from "./_shared/logger.ts";
import { checkDeviceSubscription } from "./_shared/subscription-check.ts";
import { isValidPublicUrl } from "./_shared/url-utils.ts";
import { runPipeline, PipelineContext } from "./_shared/pipeline-orchestrator.ts";

const corsHeaders = {
    "Access-Control-Allow-Origin": "*",
    "Access-Control-Allow-Headers": "authorization, x-client-info, apikey, content-type",
};

interface GenerateVideoRequest {
    device_id: string;
    effect_id: string;
    input_image_url: string;
    secondary_image_url?: string;
    user_prompt?: string;
}

interface EffectRecord {
    id: string;
    name: string;
    is_active: boolean;
    requires_secondary_photo: boolean;
    system_prompt_template: string;
    provider: string;
    ai_model_id?: string;
    generation_params: Record<string, unknown>;
}

interface GrokStartResponse {
    request_id?: string;
    error?: { message?: string };
}

interface ProviderConfig {
    default_duration?: number;
    default_resolution?: string;
    default_aspect_ratio?: string;
    default_model_id?: string;
    poll_interval_seconds?: number;
    poll_timeout_minutes?: number;
}

async function loadProviderConfig(
    supabase: ReturnType<typeof createClient>,
    provider: string,
): Promise<ProviderConfig> {
    const { data } = await supabase
        .from("provider_config")
        .select("config")
        .eq("provider", provider)
        .maybeSingle();
    return (data?.config as ProviderConfig) ?? {};
}

serve(async (req) => {
    const logger = new Logger('generate-video');

    if (req.method === "OPTIONS") {
        return new Response(null, { headers: corsHeaders });
    }

    try {
        logger.info('request.received', { metadata: { method: req.method } });

        const supabaseUrl = Deno.env.get("SUPABASE_URL")!;
        const supabaseKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY")!;
        const supabase = createClient(supabaseUrl, supabaseKey);
        const body: GenerateVideoRequest = await req.json();

        const {
            device_id,
            effect_id,
            input_image_url,
            secondary_image_url,
            user_prompt,
        } = body;

        logger.info('request.parsed', {
            metadata: { device_id, effect_id, has_prompt: !!user_prompt, has_secondary: !!secondary_image_url }
        });

        if (!device_id || !effect_id || !input_image_url) {
            logger.warn('validation.failed.missing_fields', { metadata: { device_id: !!device_id, effect_id: !!effect_id, input_image_url: !!input_image_url } });
            return new Response(
                JSON.stringify({ error: "Missing required fields: device_id, effect_id, input_image_url", request_id: logger.getRequestId() }),
                { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
            );
        }

        if (!isValidPublicUrl(input_image_url)) {
            logger.warn('validation.invalid_primary_url', { metadata: { url_prefix: input_image_url.substring(0, 30) } });
            return new Response(
                JSON.stringify({ error: "input_image_url must be a publicly accessible HTTP(S) URL.", error_code: "INVALID_URL", request_id: logger.getRequestId() }),
                { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
            );
        }

        if (secondary_image_url && !isValidPublicUrl(secondary_image_url)) {
            logger.warn('validation.invalid_secondary_url', { metadata: { url_prefix: secondary_image_url.substring(0, 30) } });
            return new Response(
                JSON.stringify({ error: "secondary_image_url must be a publicly accessible HTTP(S) URL.", error_code: "INVALID_URL", request_id: logger.getRequestId() }),
                { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
            );
        }

        const { data: effect, error: effectError } = await supabase
            .from('effects')
            .select('*')
            .eq('id', effect_id)
            .single();

        if (effectError || !effect) {
            logger.error('effect.fetch_failed', effectError || new Error(`Effect not found: ${effect_id}`));
            return new Response(
                JSON.stringify({ error: "Effect not found or invalid", error_code: "EFFECT_NOT_FOUND", request_id: logger.getRequestId() }),
                { status: 404, headers: { ...corsHeaders, "Content-Type": "application/json" } }
            );
        }

        if (!effect.is_active) {
            logger.warn('effect.inactive', { metadata: { effect_id } });
            return new Response(
                JSON.stringify({ error: "This effect is no longer active", error_code: "EFFECT_INACTIVE", request_id: logger.getRequestId() }),
                { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
            );
        }

        if (effect.requires_secondary_photo && !secondary_image_url) {
            logger.warn('validation.failed.missing_secondary', { metadata: { effect_id } });
            return new Response(
                JSON.stringify({ error: "This effect requires a secondary photo.", error_code: "MISSING_SECONDARY_PHOTO", request_id: logger.getRequestId() }),
                { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
            );
        }

        let finalPrompt = effect.system_prompt_template;
        if (finalPrompt.includes('{{user_prompt}}')) {
            if (user_prompt && user_prompt.trim().length > 0) {
                finalPrompt = finalPrompt.replace('{{user_prompt}}', user_prompt.trim());
            } else {
                finalPrompt = finalPrompt.replace('{{user_prompt}}', '').trim();
            }
        }

        let { data: device } = await supabase
            .from("devices")
            .select("id")
            .eq("device_id", device_id)
            .single();

        if (!device) {
            logger.info('device.creating', { metadata: { device_id } });
            const { data: newDevice, error: insertError } = await supabase
                .from("devices")
                .insert({ device_id })
                .select("id")
                .single();

            if (insertError) {
                logger.error('device.create_failed', insertError);
                return new Response(
                    JSON.stringify({ error: "Failed to create device record", request_id: logger.getRequestId(), details: insertError }),
                    { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } }
                );
            }
            device = newDevice;
            logger.info('device.created', { metadata: { device_uuid: device.id } });
        }

        const subscriptionCheck = await checkDeviceSubscription(supabase, device.id, device_id);

        if (!subscriptionCheck.valid) {
            logger.warn('subscription.invalid', {
                metadata: { error_code: subscriptionCheck.errorCode, error: subscriptionCheck.error, device_id }
            });

            const statusCode = subscriptionCheck.errorCode === "LIMIT_REACHED" ? 429 : 403;

            return new Response(
                JSON.stringify({
                    error: subscriptionCheck.error,
                    error_code: subscriptionCheck.errorCode,
                    limit: subscriptionCheck.generationLimit,
                    period_days: subscriptionCheck.periodDays,
                    used: subscriptionCheck.generationsUsed,
                    remaining: subscriptionCheck.generationsRemaining,
                    request_id: logger.getRequestId()
                }),
                { status: statusCode, headers: { ...corsHeaders, "Content-Type": "application/json" } }
            );
        }

        const { data: generation, error: genError } = await supabase
            .from("generations")
            .insert({
                device_id: device.id,
                effect_id: effect_id,
                input_image_url: input_image_url,
                secondary_image_url: secondary_image_url || null,
                reference_video_url: null,
                prompt: finalPrompt,
                status: "pending",
                provider: "grok",
                request_id: logger.getRequestId(),
                input_payload: { user_prompt: user_prompt ?? null },
                error_log: [],
            })
            .select()
            .single();

        if (genError) {
            logger.error('generation.create_failed', genError);
            return new Response(
                JSON.stringify({ error: "Failed to create generation record", request_id: logger.getRequestId(), details: genError }),
                { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } }
            );
        }

        logger.setGenerationId(generation.id);
        logger.info('generation.created', { generation_id: generation.id });

        // --- Pipeline routing: check if this effect has an active pipeline ---
        const { data: effectPipeline } = await supabase
            .from("effect_pipelines")
            .select("pipeline_id, config_overrides, pipeline_templates!inner(id, is_active)")
            .eq("effect_id", effect_id)
            .eq("is_active", true)
            .limit(1)
            .maybeSingle();

        if (effectPipeline?.pipeline_id) {
            logger.info('pipeline.routing', { metadata: { pipeline_id: effectPipeline.pipeline_id } });

            try {
                const pipelineContext: PipelineContext = {
                    user_image: input_image_url,
                    user_prompt: user_prompt || "",
                    effect_id,
                    effect_name: effect.name,
                    effect_concept: effect.system_prompt_template,
                    ...(secondary_image_url ? { secondary_image: secondary_image_url } : {}),
                };

                const pipelineResult = await runPipeline(
                    effectPipeline.pipeline_id,
                    generation.id,
                    pipelineContext,
                    supabase,
                    logger,
                );

                if (pipelineResult.providerRequestId) {
                    await supabase.from("generations").update({
                        status: "processing",
                        prompt: pipelineResult.finalPrompt || finalPrompt,
                        provider_request_id: pipelineResult.providerRequestId,
                        api_response: {
                            provider: "grok",
                            request_id: pipelineResult.providerRequestId,
                            pipeline_execution_id: pipelineResult.pipelineExecutionId,
                        },
                        error_log: logger.getLogs(),
                    }).eq("id", generation.id);

                    return new Response(
                        JSON.stringify({
                            success: true,
                            generation_id: generation.id,
                            status: "processing",
                            pipeline_execution_id: pipelineResult.pipelineExecutionId,
                            api_response: {
                                provider: "grok",
                                request_id: pipelineResult.providerRequestId,
                            },
                            request_id: logger.getRequestId(),
                        }),
                        { headers: { ...corsHeaders, "Content-Type": "application/json" } }
                    );
                } else {
                    await supabase.from("generations").update({
                        status: "completed",
                        error_log: logger.getLogs(),
                    }).eq("id", generation.id);

                    return new Response(
                        JSON.stringify({
                            success: true,
                            generation_id: generation.id,
                            status: "completed",
                            pipeline_execution_id: pipelineResult.pipelineExecutionId,
                            request_id: logger.getRequestId(),
                        }),
                        { headers: { ...corsHeaders, "Content-Type": "application/json" } }
                    );
                }
            } catch (pipelineError) {
                const errMsg = pipelineError instanceof Error ? pipelineError.message : String(pipelineError);
                logger.error('pipeline.failed', pipelineError instanceof Error ? pipelineError : new Error(errMsg));

                await supabase.from("generations").update({
                    status: "failed",
                    error_message: `Pipeline failed: ${errMsg}`,
                    error_log: logger.getLogs(),
                }).eq("id", generation.id);

                await supabase.from("failed_generations").insert({
                    original_generation_id: generation.id,
                    device_id: device.id,
                    failure_reason: "pipeline_execution_failed",
                    final_error_message: errMsg,
                    error_log: logger.getLogs(),
                    retry_count: 0,
                });

                return new Response(
                    JSON.stringify({
                        success: false,
                        generation_id: generation.id,
                        status: "failed",
                        error: errMsg,
                        request_id: logger.getRequestId(),
                    }),
                    { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } }
                );
            }
        }

        // --- Direct-to-Grok flow (no pipeline) ---
        const grokApiKey = Deno.env.get("GROK_API_KEY");
        if (!grokApiKey) {
            logger.error('config.missing', 'GROK_API_KEY not configured');
            await supabase.from("generations").update({
                status: "failed",
                error_message: "GROK_API_KEY not configured",
                error_log: logger.getLogs(),
            }).eq("id", generation.id);
            return new Response(
                JSON.stringify({ error: "Configuration Error: GROK_API_KEY missing", request_id: logger.getRequestId() }),
                { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } }
            );
        }

        const providerCfg = await loadProviderConfig(supabase, "grok");
        const effectParams = (effect.generation_params || {}) as Record<string, unknown>;

        const grokDuration = (effectParams.duration as number) ?? providerCfg.default_duration ?? 10;
        const grokResolution = (effectParams.resolution as string) ?? providerCfg.default_resolution ?? "720p";
        const grokAspectRatio = (effectParams.aspect_ratio as string) ?? providerCfg.default_aspect_ratio ?? "9:16";

        const grokBody: Record<string, unknown> = {
            model: effect.ai_model_id || effectParams.model_id || providerCfg.default_model_id || "grok-imagine-video",
            prompt: finalPrompt,
            image: { url: input_image_url },
            duration: grokDuration,
            aspect_ratio: grokAspectRatio,
            resolution: grokResolution,
        };

        logger.info('grok.calling', { metadata: { duration: grokDuration, resolution: grokResolution, aspect_ratio: grokAspectRatio } });

        const grokCall = async (): Promise<GrokStartResponse> => {
            const res = await fetch("https://api.x.ai/v1/videos/generations", {
                method: "POST",
                headers: {
                    "Content-Type": "application/json",
                    "Authorization": `Bearer ${grokApiKey}`,
                },
                body: JSON.stringify(grokBody),
            });
            if (!res.ok) {
                const errText = await res.text();
                throw new Error(`Grok API ${res.status}: ${errText}`);
            }
            return res.json();
        };

        const retryResult = await withRetry(grokCall, logger, { maxRetries: 1 });

        if ("error" in retryResult) {
            logger.error('grok.failed_permanently', retryResult.error);
            await supabase.from("generations").update({
                status: "failed",
                error_message: retryResult.error.message,
                retry_count: retryResult.attempts,
                last_error_at: new Date().toISOString(),
                error_log: logger.getLogs(),
            }).eq("id", generation.id);

            await supabase.from("failed_generations").insert({
                original_generation_id: generation.id,
                device_id: device.id,
                failure_reason: "grok_api_call_failed",
                final_error_message: retryResult.error.message,
                error_log: logger.getLogs(),
                retry_count: retryResult.attempts,
            });

            return new Response(
                JSON.stringify({ success: false, generation_id: generation.id, status: "failed", error: retryResult.error.message, request_id: logger.getRequestId() }),
                { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } }
            );
        }

        const grokResult = retryResult.result;
        logger.info('grok.response_received', { api_response: grokResult });

        if (!grokResult.request_id) {
            const errMsg = grokResult.error?.message || "Grok did not return a request_id";
            logger.error('grok.no_request_id', errMsg);
            await supabase.from("generations").update({
                status: "failed",
                error_message: errMsg,
                api_response: grokResult,
                error_log: logger.getLogs(),
            }).eq("id", generation.id);

            return new Response(
                JSON.stringify({ success: false, generation_id: generation.id, status: "failed", error: errMsg, request_id: logger.getRequestId() }),
                { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } }
            );
        }

        await supabase.from("generations").update({
            status: "processing",
            provider_request_id: grokResult.request_id,
            api_response: { provider: "grok", request_id: grokResult.request_id },
            retry_count: retryResult.attempts,
            error_log: logger.getLogs(),
        }).eq("id", generation.id);

        logger.info('grok.generation_queued', { metadata: { grok_request_id: grokResult.request_id } });

        return new Response(
            JSON.stringify({
                success: true,
                generation_id: generation.id,
                status: "processing",
                api_response: { provider: "grok", request_id: grokResult.request_id },
                request_id: logger.getRequestId(),
            }),
            { headers: { ...corsHeaders, "Content-Type": "application/json" } }
        );

    } catch (error) {
        logger.error('request.unhandled_error', error instanceof Error ? error : new Error(String(error)));
        const errorMessage = error instanceof Error ? error.message : "Unknown error";
        return new Response(
            JSON.stringify({ error: errorMessage, request_id: logger.getRequestId(), details: error }),
            { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } }
        );
    }
});

// Structured logging utility for edge functions

export type LogLevel = 'debug' | 'info' | 'warn' | 'error';

export interface LogEntry {
  timestamp: string;
  level: LogLevel;
  event: string;
  request_id?: string;
  generation_id?: string;
  message?: string;
  duration_ms?: number;
  retry_attempt?: number;
  api_response?: unknown;
  error?: {
    message: string;
    code?: string;
    stack?: string;
  };
  metadata?: Record<string, unknown>;
}

export interface LogContext {
  request_id: string;
  generation_id?: string;
  function_name: string;
}

/**
 * Generate a unique request ID for correlation
 */
export function generateRequestId(): string {
  return `req_${Date.now()}_${Math.random().toString(36).substring(2, 9)}`;
}

/**
 * Create a structured log entry
 */
export function createLogEntry(
  level: LogLevel,
  event: string,
  context: Partial<LogContext>,
  details?: Partial<Omit<LogEntry, 'timestamp' | 'level' | 'event'>>
): LogEntry {
  return {
    timestamp: new Date().toISOString(),
    level,
    event,
    request_id: context.request_id,
    generation_id: context.generation_id,
    ...details,
  };
}

/**
 * Logger class for consistent structured logging
 */
export class Logger {
  private context: LogContext;
  private logs: LogEntry[] = [];

  constructor(functionName: string, requestId?: string) {
    this.context = {
      function_name: functionName,
      request_id: requestId || generateRequestId(),
    };
  }

  setGenerationId(id: string) {
    this.context.generation_id = id;
  }

  getRequestId(): string {
    return this.context.request_id;
  }

  getLogs(): LogEntry[] {
    return this.logs;
  }

  private log(level: LogLevel, event: string, details?: Partial<Omit<LogEntry, 'timestamp' | 'level' | 'event'>>) {
    const entry = createLogEntry(level, event, this.context, details);
    this.logs.push(entry);

    // Also output to console for Supabase logs
    const logMethod = level === 'error' ? console.error : 
                      level === 'warn' ? console.warn : 
                      level === 'debug' ? console.debug : console.info;

    logMethod(JSON.stringify(entry));
    return entry;
  }

  debug(event: string, details?: Partial<Omit<LogEntry, 'timestamp' | 'level' | 'event'>>) {
    return this.log('debug', event, details);
  }

  info(event: string, details?: Partial<Omit<LogEntry, 'timestamp' | 'level' | 'event'>>) {
    return this.log('info', event, details);
  }

  warn(event: string, details?: Partial<Omit<LogEntry, 'timestamp' | 'level' | 'event'>>) {
    return this.log('warn', event, details);
  }

  error(event: string, error: Error | string, details?: Partial<Omit<LogEntry, 'timestamp' | 'level' | 'event'>>) {
    const errorObj = error instanceof Error 
      ? { message: error.message, stack: error.stack }
      : { message: error };

    return this.log('error', event, { ...details, error: errorObj });
  }
}

/**
 * Retry with exponential backoff
 */
export interface RetryConfig {
  maxRetries: number;
  initialDelayMs: number;
  maxDelayMs: number;
  backoffMultiplier: number;
}

export const DEFAULT_RETRY_CONFIG: RetryConfig = {
  maxRetries: 3,
  initialDelayMs: 5000,
  maxDelayMs: 60000,
  backoffMultiplier: 2,
};

export async function withRetry<T>(
  fn: () => Promise<T>,
  logger: Logger,
  config: Partial<RetryConfig> = {}
): Promise<{ result: T; attempts: number } | { error: Error; attempts: number }> {
  const { maxRetries, initialDelayMs, maxDelayMs, backoffMultiplier } = {
    ...DEFAULT_RETRY_CONFIG,
    ...config,
  };

  let lastError: Error | null = null;
  let delay = initialDelayMs;

  for (let attempt = 1; attempt <= maxRetries + 1; attempt++) {
    try {
      logger.info('retry.attempt', { retry_attempt: attempt, metadata: { max_retries: maxRetries } });

      const startTime = Date.now();
      const result = await fn();
      const duration = Date.now() - startTime;

      logger.info('retry.success', { retry_attempt: attempt, duration_ms: duration });
      return { result, attempts: attempt };
    } catch (error) {
      lastError = error instanceof Error ? error : new Error(String(error));

      logger.warn('retry.failed', {
        retry_attempt: attempt,
        error: { message: lastError.message },
        metadata: { will_retry: attempt <= maxRetries, next_delay_ms: delay },
      });

      if (attempt <= maxRetries) {
        await new Promise(resolve => setTimeout(resolve, delay));
        delay = Math.min(delay * backoffMultiplier, maxDelayMs);
      }
    }
  }

  logger.error('retry.exhausted', lastError!, { metadata: { total_attempts: maxRetries + 1 } });
  return { error: lastError!, attempts: maxRetries + 1 };
}

/**
 * Helper to extract output URL from various API response formats
 */
export function extractOutputUrl(result: Record<string, unknown>): string | null {
  // Check for direct output array with actual URLs (not empty)
  if (result.output && Array.isArray(result.output) && result.output.length > 0) {
    const firstOutput = result.output[0];
    if (typeof firstOutput === 'string' && firstOutput.startsWith('http')) {
      return firstOutput;
    }
  }

  // Check for direct output string
  if (result.output && typeof result.output === 'string' && (result.output as string).startsWith('http')) {
    return result.output as string;
  }

  // Check future_links (where completed videos will eventually be available)
  if (result.future_links && Array.isArray(result.future_links) && result.future_links.length > 0) {
    return result.future_links[0] as string;
  }

  return null;
}

/**
 * Subscription validation module.
 *
 * Primary check: device_subscriptions table (populated by validate-apple-subscription).
 * Every generation request checks expires_at in real time.
 *
 * Fallback: apple_receipts table (forward compatibility for Apple Server API).
 */

import { SupabaseClient } from "https://esm.sh/@supabase/supabase-js@2";

export interface SubscriptionCheckResult {
  valid: boolean;
  planId?: string;
  generationLimit?: number;
  periodDays?: number | null;
  generationsUsed?: number;
  generationsRemaining?: number;
  error?: string;
  errorCode?: "NO_SUBSCRIPTION" | "SUBSCRIPTION_EXPIRED" | "LIMIT_REACHED";
}

function getAdminDeviceId(): string | null {
  return Deno.env.get("ADMIN_DEVICE_ID") || null;
}

async function isSubscriptionCheckEnabled(supabase: SupabaseClient): Promise<boolean> {
  const { data } = await supabase
    .from("system_config")
    .select("value")
    .eq("key", "subscription_check_enabled")
    .maybeSingle();

  if (!data) return true;

  return data.value === true || data.value === "true";
}

async function countGenerationsInPeriod(
  supabase: SupabaseClient,
  deviceUuid: string,
  periodDays: number
): Promise<number> {
  const periodStart = new Date(Date.now() - (periodDays * 24 * 60 * 60 * 1000));
  const { count } = await supabase
    .from("generations")
    .select("*", { count: "exact", head: true })
    .eq("device_id", deviceUuid)
    .gte("created_at", periodStart.toISOString());
  return count || 0;
}

async function validateGenerationLimits(
  supabase: SupabaseClient,
  deviceUuid: string,
  planId: string,
  generationLimit: number,
  periodDays: number | null
): Promise<SubscriptionCheckResult> {
  if (periodDays === null) {
    return {
      valid: true,
      planId,
      generationLimit,
      periodDays: null,
      generationsRemaining: -1,
    };
  }

  const used = await countGenerationsInPeriod(supabase, deviceUuid, periodDays);
  const remaining = Math.max(0, generationLimit - used);

  if (remaining <= 0) {
    return {
      valid: false,
      planId,
      generationLimit,
      periodDays,
      generationsUsed: used,
      generationsRemaining: 0,
      error: `Generation limit reached for plan ${planId}. Used ${used}/${generationLimit} in the last ${periodDays} days.`,
      errorCode: "LIMIT_REACHED",
    };
  }

  return {
    valid: true,
    planId,
    generationLimit,
    periodDays,
    generationsUsed: used,
    generationsRemaining: remaining,
  };
}

export async function checkDeviceSubscription(
  supabase: SupabaseClient,
  deviceUuid: string,
  deviceId: string
): Promise<SubscriptionCheckResult> {
  const adminDeviceId = getAdminDeviceId();
  if (adminDeviceId && deviceId === adminDeviceId) {
    return { valid: true, planId: "admin_override" };
  }

  const checkEnabled = await isSubscriptionCheckEnabled(supabase);
  if (!checkEnabled) {
    return { valid: true, planId: "check_disabled" };
  }

  const { data: sub } = await supabase
    .from("device_subscriptions")
    .select(`
      plan_id,
      expires_at,
      subscription_plans (
        generation_limit,
        period_days
      )
    `)
    .eq("device_id", deviceUuid)
    .maybeSingle();

  if (!sub) {
    return {
      valid: false,
      error: "No active subscription found. Please subscribe to generate videos.",
      errorCode: "NO_SUBSCRIPTION",
    };
  }

  if (sub.expires_at && new Date(sub.expires_at) < new Date()) {
    return {
      valid: false,
      error: "Your subscription has expired. Please renew to continue generating videos.",
      errorCode: "SUBSCRIPTION_EXPIRED",
    };
  }

  const plan = sub.subscription_plans as any;
  if (!plan) {
    return { valid: true, planId: sub.plan_id };
  }

  return await validateGenerationLimits(
    supabase,
    deviceUuid,
    sub.plan_id,
    plan.generation_limit,
    plan.period_days
  );
}

/**
 * Validate that a URL is a publicly accessible HTTP(S) URL.
 * Rejects file://, local paths, and other non-HTTP schemes.
 */
export function isValidPublicUrl(url: string): boolean {
  try {
    const parsed = new URL(url);
    return parsed.protocol === 'http:' || parsed.protocol === 'https:';
  } catch {
    return false;
  }
}

/**
 * Ensure a URL is properly encoded for use in external API calls.
 * Handles URLs that may contain spaces or other unencoded characters.
 * Uses encodeURI which encodes spaces but preserves URL structure (://?&#=).
 */
export function ensureEncodedUrl(url: string): string {
  try {
    // If the URL already contains encoded characters (%20, etc.), decode first to avoid double-encoding
    const decoded = decodeURI(url);
    return encodeURI(decoded);
  } catch {
    // If decoding fails (malformed), just encode as-is
    return encodeURI(url);
  }
}

import { createClient } from "https://esm.sh/@supabase/supabase-js@2";
import { Logger } from "./logger.ts";
import { executeGeminiImage } from "./providers/gemini-image.ts";
import { executeGrokVision } from "./providers/grok-vision.ts";
import { executeGrokText } from "./providers/grok-text.ts";
import { executeGrokVideo } from "./providers/grok-video.ts";

export type PipelineContext = Record<string, unknown>;

export interface PipelineStep {
  id: string;
  step_order: number;
  step_type: string;
  name: string;
  provider: string;
  config: Record<string, unknown>;
  input_mapping: Record<string, string>;
  output_mapping: Record<string, string>;
  is_required: boolean;
}

function resolveMapping(mapping: Record<string, string>, context: PipelineContext): Record<string, unknown> {
  const resolved: Record<string, unknown> = {};
  for (const [key, path] of Object.entries(mapping)) {
    if (path.startsWith("pipeline.")) {
      const contextKey = path.replace("pipeline.", "");
      resolved[key] = context[contextKey];
    } else if (path.startsWith("step.")) {
      const parts = path.split(".");
      if (parts.length >= 3) {
        const stepName = parts[1];
        const outputKey = parts.slice(2).join(".");
        const stepsContext = context.steps as Record<string, { output: Record<string, unknown> }>;
        if (stepsContext && stepsContext[stepName] && stepsContext[stepName].output) {
          resolved[key] = stepsContext[stepName].output[outputKey];
        }
      }
    } else {
      resolved[key] = path;
    }
  }
  return resolved;
}

function storeOutputs(
  stepName: string,
  output: Record<string, unknown>,
  mapping: Record<string, string>,
  context: PipelineContext
) {
  if (!context.steps) {
    context.steps = {};
  }
  const stepsContext = context.steps as Record<string, { output: Record<string, unknown> }>;
  if (!stepsContext[stepName]) {
    stepsContext[stepName] = { output: {} };
  }

  stepsContext[stepName].output = { ...stepsContext[stepName].output, ...output };

  for (const [outputKey, contextPath] of Object.entries(mapping)) {
    if (contextPath.startsWith("result.")) {
      const resultKey = contextPath.replace("result.", "");
      if (output[resultKey] !== undefined) {
        context[outputKey] = output[resultKey];
      }
    }
  }
}

export async function runPipeline(
  pipelineId: string,
  generationId: string,
  initialContext: PipelineContext,
  supabase: ReturnType<typeof createClient>,
  logger: Logger,
) {
  const { data: stepsData, error: stepsError } = await supabase
    .from("pipeline_steps")
    .select("*")
    .eq("pipeline_id", pipelineId)
    .eq("is_active", true)
    .order("step_order", { ascending: true });

  if (stepsError) throw new Error(`Failed to load pipeline steps: ${stepsError.message}`);
  if (!stepsData || stepsData.length === 0) throw new Error("No active steps found for pipeline");

  const steps = stepsData as PipelineStep[];
  const context = { ...initialContext };

  const { data: pipelineExecution, error: peError } = await supabase
    .from("pipeline_executions")
    .insert({
      generation_id: generationId,
      pipeline_id: pipelineId,
      status: "running",
      current_step: 0,
      total_steps: steps.length,
      context,
      started_at: new Date().toISOString(),
    })
    .select()
    .single();

  if (peError) throw new Error(`Failed to create pipeline execution: ${peError.message}`);
  const pipelineExecutionId = pipelineExecution.id;

  logger.info("pipeline.steps_loaded", { metadata: { step_count: steps.length } });

  let lastProviderRequestId: string | null = null;
  let grokVideoAttempts = 0;

  for (let i = 0; i < steps.length; i++) {
    const step = steps[i];
    const startTime = Date.now();

    logger.info("pipeline.step.start", {
      metadata: { step_name: step.name, step_type: step.step_type, step_order: step.step_order },
    });

    await supabase
      .from("pipeline_executions")
      .update({ current_step: i + 1, context })
      .eq("id", pipelineExecutionId);

    try {
      const inputs = resolveMapping(step.input_mapping, context);
      let output: Record<string, unknown> = {};

      if (step.step_type === "image_enhance" && step.provider === "gemini") {
        const res = await executeGeminiImage(
          {
            imageUrl: inputs.image as string,
            prompt: (step.config.prompt_template as string).replace("{{user_prompt}}", (inputs.user_prompt as string) || ""),
            model: step.config.model as string,
            quality: step.config.quality as string,
          },
          supabase,
          logger,
          pipelineExecutionId
        );
        output = { image_url: res.imageUrl, storage_path: res.storagePath };

      } else if (step.step_type === "image_analyze" && step.provider === "grok") {
        const res = await executeGrokVision(
          {
            imageUrl: inputs.image as string,
            prompt: step.config.prompt_template as string,
            model: step.config.model as string,
            maxTokens: step.config.max_tokens as number,
          },
          logger
        );
        output = { image_description: res.description };

      } else if (step.step_type === "prompt_enrich" && step.provider === "grok") {
        let prompt = step.config.prompt_template as string;
        prompt = prompt.replace("{{image_description}}", (inputs.prompt_context as string) || "");
        prompt = prompt.replace("{{effect_concept}}", (context.effect_concept as string) || "");
        prompt = prompt.replace("{{user_prompt}}", (context.user_prompt as string) || "");

        const res = await executeGrokText(
          {
            prompt,
            model: step.config.model as string,
            maxTokens: step.config.max_tokens as number,
          },
          logger
        );
        output = { enriched_prompt: res.text };

      } else if (step.step_type === "video_generate" && step.provider === "grok") {
        const res = await executeGrokVideo(
          {
            imageUrl: inputs.image as string,
            prompt: inputs.prompt as string,
            model: step.config.model as string,
            duration: step.config.duration as number,
            aspectRatio: step.config.aspect_ratio as string,
          },
          logger
        );
        output = { request_id: res.requestId };
        lastProviderRequestId = res.requestId;
        grokVideoAttempts = 1;
      } else {
        throw new Error(`Unsupported step type/provider combination: ${step.step_type}/${step.provider}`);
      }

      storeOutputs(step.name, output, step.output_mapping, context);

      logger.info("pipeline.step.completed", {
        metadata: { step_type: step.step_type, step_order: step.step_order, duration_ms: Date.now() - startTime },
      });

    } catch (err) {
      const errorMsg = err instanceof Error ? err.message : String(err);

      await supabase
        .from("pipeline_executions")
        .update({
          status: "failed",
          error_message: `Step "${step.name}" failed: ${errorMsg}`,
          context,
        })
        .eq("id", pipelineExecutionId);

      if (step.is_required) {
        throw new Error(`Pipeline step "${step.name}" failed: ${errorMsg}`);
      } else {
        logger.warn("pipeline.step.failed_but_continuing", {
          metadata: { step_name: step.name, error: errorMsg },
        });
      }
    }
  }

  const finalStatus = lastProviderRequestId ? "running" : "completed";

  await supabase
    .from("pipeline_executions")
    .update({
      status: finalStatus,
      context,
      step_results: steps.map(s => ({
        step_id: s.id,
        step_type: s.step_type,
        name: s.name,
      })),
      ...(finalStatus === "completed" ? { completed_at: new Date().toISOString() } : {}),
    })
    .eq("id", pipelineExecutionId);

  logger.info("pipeline.orchestration_done", {
    metadata: {
      pipeline_execution_id: pipelineExecutionId,
      status: finalStatus,
      has_video_request: !!lastProviderRequestId,
    },
  });

  return {
    pipelineExecutionId,
    providerRequestId: lastProviderRequestId,
    finalPrompt: (context.enriched_prompt as string) || (context.effect_concept as string),
    finalImageUrl: (context.enhanced_image as string) || context.user_image,
    context,
    grokVideoAttempts,
  };
}

import { createClient } from "https://esm.sh/@supabase/supabase-js@2";
import { Logger } from "../logger.ts";

export interface GeminiImageInput {
  imageUrl: string;
  prompt: string;
  model?: string;
  quality?: string;
}

export interface GeminiImageOutput {
  imageUrl: string;
  storagePath: string;
}

async function fetchImageAsBase64(url: string): Promise<{ base64: string; mimeType: string }> {
  const res = await fetch(url);
  if (!res.ok) throw new Error(`Failed to fetch image: HTTP ${res.status}`);
  const buffer = await res.arrayBuffer();
  const bytes = new Uint8Array(buffer);
  const mimeType = res.headers.get("content-type") || "image/jpeg";

  let binary = "";
  for (let i = 0; i < bytes.length; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return { base64: btoa(binary), mimeType };
}

export async function executeGeminiImage(
  input: GeminiImageInput,
  supabase: ReturnType<typeof createClient>,
  logger: Logger,
  executionId: string,
): Promise<GeminiImageOutput> {
  const apiKey = Deno.env.get("GEMINI_API_KEY");
  if (!apiKey) throw new Error("GEMINI_API_KEY not configured");

  const model = input.model || "gemini-imagen-3.0";
  logger.info("gemini.image.start", { metadata: { model, prompt_length: input.prompt.length } });

  const { base64, mimeType } = await fetchImageAsBase64(input.imageUrl);
  logger.info("gemini.image.fetched_source", { metadata: { mime: mimeType } });

  const apiUrl = `https://generativelanguage.googleapis.com/v1beta/models/${model}:generateContent?key=${apiKey}`;

  const body = {
    contents: [
      {
        parts: [
          { text: input.prompt },
          { inline_data: { mime_type: mimeType, data: base64 } },
        ],
      },
    ],
    generationConfig: {
      responseModalities: ["IMAGE", "TEXT"],
      temperature: 0.4,
    },
  };

  const res = await fetch(apiUrl, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(body),
  });

  if (!res.ok) {
    const errText = await res.text();
    throw new Error(`Gemini API ${res.status}: ${errText}`);
  }

  const data = await res.json();
  logger.info("gemini.image.response_received");

  const candidates = data.candidates;
  if (!candidates?.length) throw new Error("Gemini returned no candidates");

  let resultBase64: string | null = null;
  let resultMime = "image/png";

  for (const part of candidates[0].content?.parts || []) {
    if (part.inline_data) {
      resultBase64 = part.inline_data.data;
      resultMime = part.inline_data.mime_type || "image/png";
      break;
    }
  }

  if (!resultBase64) throw new Error("Gemini response contained no image data");

  const ext = resultMime.includes("png") ? "png" : "jpg";
  const storagePath = `pipeline/${executionId}/enhanced.${ext}`;

  let binary = "";
  const decoded = atob(resultBase64);
  for (let i = 0; i < decoded.length; i++) {
    binary += String.fromCharCode(decoded.charCodeAt(i));
  }
  const imageBytes = new Uint8Array(decoded.length);
  for (let i = 0; i < decoded.length; i++) {
    imageBytes[i] = decoded.charCodeAt(i);
  }

  const { error: uploadErr } = await supabase.storage
    .from("pipeline-artifacts")
    .upload(storagePath, imageBytes, { contentType: resultMime, upsert: true });

  if (uploadErr) throw new Error(`Storage upload failed: ${uploadErr.message}`);

  const { data: publicUrlData } = supabase.storage
    .from("pipeline-artifacts")
    .getPublicUrl(storagePath);

  const imageUrl = publicUrlData.publicUrl;
  logger.info("gemini.image.completed", { metadata: { storage_path: storagePath, url: imageUrl } });

  return { imageUrl, storagePath };
}

import { Logger } from "../logger.ts";

export interface GrokVisionInput {
  imageUrl: string;
  prompt: string;
  model?: string;
  maxTokens?: number;
}

export interface GrokVisionOutput {
  description: string;
}

export async function executeGrokVision(
  input: GrokVisionInput,
  logger: Logger,
): Promise<GrokVisionOutput> {
  const apiKey = Deno.env.get("GROK_API_KEY");
  if (!apiKey) throw new Error("GROK_API_KEY not configured");

  const model = input.model || "grok-2-vision-1212";
  logger.info("grok.vision.start", { metadata: { model, prompt_length: input.prompt.length } });

  const body = {
    model,
    messages: [
      {
        role: "user",
        content: [
          { type: "image_url", image_url: { url: input.imageUrl } },
          { type: "text", text: input.prompt },
        ],
      },
    ],
    max_tokens: input.maxTokens || 500,
    temperature: 0.3,
  };

  const res = await fetch("https://api.x.ai/v1/chat/completions", {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "Authorization": `Bearer ${apiKey}`,
    },
    body: JSON.stringify(body),
  });

  if (!res.ok) {
    const errText = await res.text();
    throw new Error(`Grok Vision API ${res.status}: ${errText}`);
  }

  const data = await res.json();
  const description = data.choices?.[0]?.message?.content?.trim();
  if (!description) throw new Error("Grok Vision returned no content");

  logger.info("grok.vision.completed", { metadata: { description_length: description.length } });
  return { description };
}

